// networkModule.js
// React Native Networking Module for API and IoT Device Communication

const API_BASE_URL = 'https://api.example.com';
const DEFAULT_TIMEOUT = 10000;
const IOT_TIMEOUT = 5000;

// Allowed IoT device IP range validation
const IOT_SUBNET_PREFIX = '192.168.';
const ALLOWED_IOT_PORTS = [80, 443, 8080, 8443];

// Token storage (in production, use react-native-keychain or similar secure storage)
let authToken = null;
let refreshToken = null;

const sanitizeInput = (input) => {
  if (typeof input === 'string') {
    return input.replace(/[<>\"';&|`$(){}]/g, '');
  }
  return input;
};

const sanitizeObject = (obj) => {
  if (obj === null || obj === undefined) return obj;
  if (typeof obj !== 'object') return sanitizeInput(obj);

  const sanitized = Array.isArray(obj) ? [] : {};
  for (const key of Object.keys(obj)) {
    const sanitizedKey = sanitizeInput(key);
    sanitized[sanitizedKey] = sanitizeObject(obj[key]);
  }
  return sanitized;
};

const isValidIoTAddress = (url) => {
  try {
    const parsed = new URL(url);
    const hostname = parsed.hostname;

    if (!hostname.startsWith(IOT_SUBNET_PREFIX)) {
      return false;
    }

    // Validate it's a proper private IP (192.168.0.0 - 192.168.255.255)
    const parts = hostname.split('.');
    if (parts.length !== 4) return false;

    for (let i = 0; i < 4; i++) {
      const num = parseInt(parts[i], 10);
      if (isNaN(num) || num < 0 || num > 255) return false;
      if (parts[i] !== String(num)) return false; // Prevent octal/hex tricks
    }

    // Validate port if specified
    if (parsed.port && !ALLOWED_IOT_PORTS.includes(parseInt(parsed.port, 10))) {
      return false;
    }

    // Only allow http and https protocols
    if (parsed.protocol !== 'http:' && parsed.protocol !== 'https:') {
      return false;
    }

    return true;
  } catch {
    return false;
  }
};

const isValidApiUrl = (url) => {
  try {
    const parsed = new URL(url);
    return (
      parsed.origin === API_BASE_URL &&
      parsed.protocol === 'https:'
    );
  } catch {
    return false;
  }
};

const validateUrl = (url, type) => {
  if (type === 'api') {
    if (!isValidApiUrl(url)) {
      throw new NetworkError('Invalid API URL', 'INVALID_URL');
    }
  } else if (type === 'iot') {
    if (!isValidIoTAddress(url)) {
      throw new NetworkError('Invalid IoT device address', 'INVALID_IOT_ADDRESS');
    }
  } else {
    throw new NetworkError('Unknown request type', 'INVALID_TYPE');
  }
};

class NetworkError extends Error {
  constructor(message, code, statusCode = null, responseBody = null) {
    super(message);
    this.name = 'NetworkError';
    this.code = code;
    this.statusCode = statusCode;
    this.responseBody = responseBody;
  }
}

const fetchWithTimeout = (url, options, timeout) => {
  const controller = new AbortController();
  const { signal } = controller;

  const timeoutId = setTimeout(() => controller.abort(), timeout);

  return fetch(url, { ...options, signal })
    .then((response) => {
      clearTimeout(timeoutId);
      return response;
    })
    .catch((error) => {
      clearTimeout(timeoutId);
      if (error.name === 'AbortError') {
        throw new NetworkError('Request timed out', 'TIMEOUT');
      }
      throw error;
    });
};

// Rate limiting for IoT devices
const iotRateLimiter = (() => {
  const requests = new Map();
  const MAX_REQUESTS_PER_SECOND = 10;
  const WINDOW_MS = 1000;

  return {
    check(deviceIp) {
      const now = Date.now();
      const deviceRequests = requests.get(deviceIp) || [];

      // Clean old entries
      const recentRequests = deviceRequests.filter(
        (timestamp) => now - timestamp < WINDOW_MS
      );

      if (recentRequests.length >= MAX_REQUESTS_PER_SECOND) {
        throw new NetworkError(
          'Rate limit exceeded for IoT device',
          'RATE_LIMITED'
        );
      }

      recentRequests.push(now);
      requests.set(deviceIp, recentRequests);
    },

    reset() {
      requests.clear();
    },
  };
})();

// Retry logic with exponential backoff
const retryWithBackoff = async (fn, maxRetries = 3, baseDelay = 1000) => {
  let lastError;

  for (let attempt = 0; attempt <= maxRetries; attempt++) {
    try {
      return await fn();
    } catch (error) {
      lastError = error;

      // Don't retry on client errors (4xx) or validation errors
      if (
        error.statusCode &&
        error.statusCode >= 400 &&
        error.statusCode < 500
      ) {
        throw error;
      }

      if (error.code === 'INVALID_URL' || error.code === 'INVALID_IOT_ADDRESS' || error.code === 'RATE_LIMITED') {
        throw error;
      }

      if (attempt < maxRetries) {
        const delay = baseDelay * Math.pow(2, attempt) + Math.random() * 100;
        await new Promise((resolve) => setTimeout(resolve, delay));
      }
    }
  }

  throw lastError;
};

const parseResponseSafely = async (response) => {
  const contentType = response.headers.get('content-type') || '';
  const text = await response.text();

  // Limit response size (5MB)
  if (text.length > 5 * 1024 * 1024) {
    throw new NetworkError('Response too large', 'RESPONSE_TOO_LARGE');
  }

  if (contentType.includes('application/json')) {
    try {
      return JSON.parse(text);
    } catch {
      throw new NetworkError('Invalid JSON response', 'PARSE_ERROR');
    }
  }

  return text;
};

// ==================== API Communication ====================

const apiRequest = async (endpoint, options = {}) => {
  const {
    method = 'GET',
    body = null,
    headers = {},
    timeout = DEFAULT_TIMEOUT,
    retry = true,
    maxRetries = 3,
  } = options;

  const url = `${API_BASE_URL}${endpoint}`;
  validateUrl(url, 'api');

  const requestHeaders = {
    'Content-Type': 'application/json',
    Accept: 'application/json',
    'X-Request-ID': generateRequestId(),
    ...headers,
  };

  if (authToken) {
    requestHeaders['Authorization'] = `Bearer ${authToken}`;
  }

  const fetchOptions = {
    method: method.toUpperCase(),
    headers: requestHeaders,
    credentials: 'omit', // Don't send cookies to prevent CSRF
  };

  if (body && ['POST', 'PUT', 'PATCH'].includes(fetchOptions.method)) {
    const sanitizedBody = sanitizeObject(body);
    fetchOptions.body = JSON.stringify(sanitizedBody);
  }

  const makeRequest = async () => {
    const response = await fetchWithTimeout(url, fetchOptions, timeout);

    if (response.status === 401 && refreshToken) {
      const refreshed = await refreshAuthToken();
      if (refreshed) {
        requestHeaders['Authorization'] = `Bearer ${authToken}`;
        const retryResponse = await fetchWithTimeout(
          url,
          { ...fetchOptions, headers: requestHeaders },
          timeout
        );
        return handleApiResponse(retryResponse);
      }
    }

    return handleApiResponse(response);
  };

  if (retry) {
    return retryWithBackoff(makeRequest, maxRetries);
  }

  return makeRequest();
};

const handleApiResponse = async (response) => {
  const data = await parseResponseSafely(response);

  if (!response.ok) {
    throw new NetworkError(
      data?.message || `API error: ${response.status}`,
      data?.code || 'API_ERROR',
      response.status,
      data
    );
  }

  return {
    data,
    status: response.status,
    headers: Object.fromEntries(response.headers.entries()),
  };
};

const refreshAuthToken = async () => {
  try {
    const response = await fetchWithTimeout(
      `${API_BASE_URL}/auth/refresh`,
      {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          Accept: 'application/json',
        },
        body: JSON.stringify({ refreshToken }),
        credentials: 'omit',
      },
      DEFAULT_TIMEOUT
    );

    if (response.ok) {
      const data = await parseResponseSafely(response);
      authToken = data.accessToken;
      refreshToken = data.refreshToken;
      return true;
    }

    // Refresh failed - clear tokens
    authToken = null;
    refreshToken = null;
    return false;
  } catch {
    authToken = null;
    refreshToken = null;
    return false;
  }
};

// ==================== IoT Device Communication ====================

const iotRequest = async (deviceIp, endpoint, options = {}) => {
  const {
    method = 'GET',
    body = null,
    headers = {},
    timeout = IOT_TIMEOUT,
    useHttps = false,
    port = null,
    retry = true,
    maxRetries = 2,
    apiKey = null,
  } = options;

  const protocol = useHttps ? 'https' : 'http';
  const portSuffix = port ? `:${port}` : '';
  const sanitizedEndpoint = encodeURI(sanitizeInput(endpoint));
  const url = `${protocol}://${deviceIp}${portSuffix}${sanitizedEndpoint}`;

  validateUrl(url, 'iot');

  // Rate limit check
  iotRateLimiter.check(deviceIp);

  const requestHeaders = {
    'Content-Type': 'application/json',
    Accept: 'application/json',
    'X-Request-ID': generateRequestId(),
    ...headers,
  };

  // IoT device authentication via API key
  if (apiKey) {
    requestHeaders['X-API-Key'] = apiKey;
  }

  const fetchOptions = {
    method: method.toUpperCase(),
    headers: requestHeaders,
    credentials: 'omit',
  };

  if (body && ['POST', 'PUT', 'PATCH'].includes(fetchOptions.method)) {
    const sanitizedBody = sanitizeObject(body);
    fetchOptions.body = JSON.stringify(sanitizedBody);
  }

  const makeRequest = async () => {
    try {
      const response = await fetchWithTimeout(url, fetchOptions, timeout);
      return handleIoTResponse(response, deviceIp);
    } catch (error) {
      if (error instanceof NetworkError) throw error;

      throw new NetworkError(
        `IoT device unreachable: ${deviceIp}`,
        'IOT_UNREACHABLE',
        null,
        { originalError: error.message }
      );
    }
  };

  if (retry) {
    return retryWithBackoff(makeRequest, maxRetries, 500);
  }

  return makeRequest();
};

const handleIoTResponse = async (response, deviceIp) => {
  const data = await parseResponseSafely(response);

  if (!response.ok) {
    throw new NetworkError(
      `IoT device error (${deviceIp}): ${response.status}`,
      'IOT_ERROR',
      response.status,
      data
    );
  }

  return {
    data,
    status: response.status,
    deviceIp,
    headers: Object.fromEntries(response.headers.entries()),
  };
};

// ==================== IoT Device Discovery ====================

const discoverDevices = async (subnet = '192.168.1', portToScan = 80, concurrency = 10) => {
  // Validate subnet
  const subnetParts = subnet.split('.');
  if (
    subnetParts.length !== 3 ||
    !subnet.startsWith('192.168.') ||
    subnetParts.some((p) => isNaN(parseInt(p, 10)) || parseInt(p, 10) < 0 || parseInt(p, 10) > 255)
  ) {
    throw new NetworkError('Invalid subnet for discovery', 'INVALID_SUBNET');
  }

  if (!ALLOWED_IOT_PORTS.includes(portToScan)) {
    throw new NetworkError('Port not allowed for IoT scanning', 'INVALID_PORT');
  }

  const devices = [];
  const ips = Array.from({ length: 254 }, (_, i) => `${subnet}.${i + 1}`);

  // Process in batches to limit concurrency
  for (let i = 0; i < ips.length; i += concurrency) {
    const batch = ips.slice(i, i + concurrency);
    const results = await Promise.allSettled(
      batch.map(async (ip) => {
        try {
          const url = `http://${ip}:${portToScan}/api/device/info`;
          const response = await fetchWithTimeout(
            url,
            {
              method: 'GET',
              headers: { Accept: 'application/json' },
              credentials: 'omit',
            },
            2000
          );

          if (response.ok) {
            const data = await parseResponseSafely(response);
            return { ip, port: portToScan, info: data };
          }
          return null;
        } catch {
          return null;
        }
      })
    );

    results.forEach((result) => {
      if (result.status === 'fulfilled' && result.value) {
        devices.push(result.value);
      }
    });
  }

  return devices;
};

// ==================== Utility Functions ====================

const generateRequestId = () => {
  const timestamp = Date.now().toString(36);
  const randomPart = Math.random().toString(36).substring(2, 10);
  return `${timestamp}-${randomPart}`;
};

// ==================== Auth Management ====================

const setAuthTokens = (access, refresh) => {
  if (typeof access !== 'string' || typeof refresh !== 'string') {
    throw new NetworkError('Invalid token format', 'INVALID_TOKEN');
  }
  // Basic JWT format validation
  if (access.split('.').length !== 3 || refresh.split('.').length !== 3) {
    throw new NetworkError('Invalid JWT format', 'INVALID_TOKEN');
  }
  authToken = access;
  refreshToken = refresh;
};

const clearAuthTokens = () => {
  authToken = null;
  refreshToken = null;
};

const isAuthenticated = () => {
  return authToken !== null;
};

// ==================== High-Level API Methods ====================

const api = {
  get: (endpoint, options = {}) =>
    apiRequest(endpoint, { ...options, method: 'GET' }),

  post: (endpoint, body, options = {}) =>
    apiRequest(endpoint, { ...options, method: 'POST', body }),

  put: (endpoint, body, options = {}) =>
    apiRequest(endpoint, { ...options, method: 'PUT', body }),

  patch: (endpoint, body, options = {}) =>
    apiRequest(endpoint, { ...options, method: 'PATCH', body }),

  delete: (endpoint, options = {}) =>
    apiRequest(endpoint, { ...options, method: 'DELETE' }),
};

// ==================== High-Level IoT Methods ====================

const iot = {
  get: (deviceIp, endpoint, options = {}) =>
    iotRequest(deviceIp, endpoint, { ...options, method: 'GET' }),

  post: (deviceIp, endpoint, body, options = {}) =>
    iotRequest(deviceIp, endpoint, { ...options, method: 'POST', body }),

  put: (deviceIp, endpoint, body, options = {}) =>
    iotRequest(deviceIp, endpoint, { ...options, method: 'PUT', body }),

  getDeviceStatus: (deviceIp, options = {}) =>
    iotRequest(deviceIp, '/api/status', { ...options, method: 'GET' }),

  getDeviceInfo: (deviceIp, options = {}) =>
    iotRequest(deviceIp, '/api/device/info', { ...options, method: 'GET' }),

  sendCommand: (deviceIp, command, params = {}, options = {}) =>
    iotRequest(deviceIp, '/api/command', {
      ...options,
      method: 'POST',
      body: { command: sanitizeInput(command), params: sanitizeObject(params) },
    }),

  updateFirmware: (deviceIp, firmwareUrl, options = {}) => {
    // Validate firmware URL points to our API
    if (!firmwareUrl.startsWith(API_BASE_URL)) {
      throw new NetworkError(
        'Firmware URL must point to the official API',
        'INVALID_FIRMWARE_URL'
      );
    }
    return iotRequest(deviceIp, '/api/firmware/update', {
      ...options,
      method: 'POST',
      body: { firmwareUrl },
      timeout: 30000,
    });
  },

  discover: discoverDevices,
};

// ==================== Login Helper ====================

const login = async (username, password) => {
  const response = await apiRequest('/auth/login', {
    method: 'POST',
    body: {
      username: sanitizeInput(username),
      password, // Don't sanitize password as it may contain special chars
    },
    retry: false,
  });

  if (response.data.accessToken && response.data.refreshToken) {
    setAuthTokens(response.data.accessToken, response.data.refreshToken);
  }

  return response;
};

const logout = async () => {
  try {
    if (authToken) {
      await apiRequest('/auth/logout', {
        method: 'POST',
        retry: false,
      });
    }
  } finally {
    clearAuthTokens();
  }
};

// ==================== Health Check ====================

const healthCheck = async () => {
  const results = {
    api: false,
    timestamp: new Date().toISOString(),
  };

  try {
    const response = await apiRequest('/health', {
      method: 'GET',
      timeout: 5000,
      retry: false,
    });
    results.api = response.status === 200;
  } catch {
    results.api = false;
  }

  return results;
};

